def range_summary(nums):
    if not nums:
        return ''

    nums.sort()
    result = []
    start = nums[0]

    for num in nums[1:]:
        if num != start + 1:
            if start == num:
                result.append(str(start))
            else:
                result.append(f'{start}-{num-1}')
            start = num

    if start == nums[-1]:
        result.append(str(start))
    else:
        result.append(f'{start}-{nums[-1]}')

    return ', '.join(result)
